1	// Nightly export of completed tasks to TSV (run with: node scripts/export_tasks.js).
2	
3	'use strict';
4	
5	const DEFAULT_LIMIT = 500;
6	
7	function formatTaskRow(task) {
8	  const status = task.completedAt ? 'done' : 'open';
9	  const title = task.title.replace(/\t/g, ' ');
10	  return [task.id, status, title].join('\t');
11	}
12	
13	class TaskExporter {
14	  constructor(baseUrl, limit = DEFAULT_LIMIT) {
15	    this.baseUrl = baseUrl;
16	    this.limit = limit;
17	  }
18	
19	  async fetchCompleted() {
20	    const res = await fetch(`${this.baseUrl}/tasks?status=done&limit=${this.limit}`);
21	    if (!res.ok) {
22	      throw new Error(`export failed: HTTP ${res.status}`);
23	    }
24	    return res.json();
25	  }
26	
27	  async exportTsv(stream) {
28	    const tasks = await this.fetchCompleted();
29	    for (const task of tasks) {
30	      stream.write(formatTaskRow(task) + '\n');
31	    }
32	    return tasks.length;
33	  }
34	}
35	
36	module.exports = { TaskExporter, formatTaskRow, DEFAULT_LIMIT };
37	
38	if (require.main === module) {
39	  const exporter = new TaskExporter(process.env.TASKHUB_URL || 'http://127.0.0.1:8080');
40	  exporter
41	    .exportTsv(process.stdout)
42	    .then((count) => process.stderr.write(`exported ${count} tasks\n`))
43	    .catch((err) => {
44	      process.stderr.write(String(err) + '\n');
45	      process.exit(1);
46	    });
47	}
